import { useState } from 'react';

const tabLabels = [
  'Профиль',
  'Уведомления',
  'История',
  'Документы',
  'Платежи',
  'Интеграции',
  'Доступы',
  'Логи'
];

const App = () => {
  const [activeTab, setActiveTab] = useState(0);

  return (
    <Tabs scrollable={true}>
      {tabLabels.map((label, index) => (
        <Tabs.Tab key={label} label={label} active={activeTab === index} onClick={() => setActiveTab(index)} />
      ))}
    </Tabs>
  );
};

export default App;
